INSERT INTO public.photos VALUES (24184, 'Estaciâ”œâ”‚n Zaragoza-Goya 2011', 'Obras de construcciâ”œâ”‚n de la estaciâ”œâ”‚n ferroviaria de cercanâ”œÂ¡as Zaragoza-Goya en 2011. Serâ”œÃ­ inaugurada el 3 de abril de 2012. Detrâ”œÃ­s, manzana de viviendas esquina Fâ”œÂ®lix Latassa con avenida Goya. Fuente: zaragozacool.wordpress.com/2011/10/08/estacion-de-goya-ob...', 2011, 2011, 2011, 'Siglo XXI', 'UNIVERSIDAD', 41.64390100, -0.89126900, '0101000020E61000003509DE904685ECBF4C6E14596BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19503258889.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19503258889.webp', 'https://www.flickr.com/photos/zaragozaantigua/19503258889/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24194, 'Râ”œÂ¡o Huerva 1936', 'Imagen de la altura que llevaba el pico de la riada de febrero de 1936, donde el metâ”œÃ­lico puente daba paso al ferrocarril de la compaâ”œâ–’â”œÂ¡a MZA (Madrid-Zaragoza-Alicante) y le daba continuidad desde Campo Sepulcro (a la izquierda), y la estaciâ”œâ”‚n de Miraflores (hacia la derecha). A la izquierda, la metâ”œÃ­lica pasarela peatonal, mâ”œÃ­s elevada, que conectaba la Avenida Central con la Gran Vâ”œÂ¡a. Fuente visual: Archivo Pâ”œâ•‘blico Municipal.', 1936, 1936, 1936, 'Anos 30', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22834803969.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22834803969.webp', 'https://www.flickr.com/photos/zaragozaantigua/22834803969/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24207, 'Fernando el Catâ”œâ”‚lico 1950', 'Aâ”œÂ®rea visual del despejado entorno del paseo de Fernando el Catâ”œâ”‚lico, desde su arranque en la zanja del ferrocarril a Barcelona, que proviene desde el fondo, la estaciâ”œâ”‚n de Zaragoza-Campo Sepulcro. Desde esta altura son perfectamente visibles los pasos que salvaban la zanja, y la delimitaciâ”œâ”‚n de solares en los que, en poco tiempo, serâ”œÂ¡an construidos modernos bloques que flanquearâ”œÃ­n el paseo. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1950, 1950, 1950, 'Anos 50', 'UNIVERSIDAD', 41.64426000, -0.89189000, '0101000020E61000005F24B4E55C8AECBF7C0F971C77D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33648251942.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33648251942.webp', 'https://www.flickr.com/photos/zaragozaantigua/33648251942/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24208, 'Avenida Goya 2011', 'Foto: Pablo Lâ”œâ”‚pez Learte. Infrecuente vista subterrâ”œÃ­nea de la avenida de Francisco de Goya, en el punto donde â”œÂ®sta pasa cubriendo el râ”œÂ¡o Huerva desde 1966. En el centro de la imagen, puente ferroviario renovado en 1959. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'UNIVERSIDAD', 41.64353800, -0.89031100, '0101000020E61000001B9C887E6D7DECBFDBDD03745FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36630416175.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36630416175.webp', 'https://www.flickr.com/photos/zaragozaantigua/36630416175/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24211, 'Av. de Goya 2011', 'Foto: Josâ”œÂ® Miguel Marco. Obras de demoliciâ”œâ”‚n de la antigua trinchera del ferrocarril entre Madrid y Barcelona, con vista a los edificios de la avenida de Goya, entre los nâ”œâ•‘meros 67 y 75, desde la iglesia del Corazâ”œâ”‚n de Marâ”œÂ¡a hasta la calle de San Antonio Marâ”œÂ¡a Claret, en mayo de 2011. Serâ”œÃ­ sustituida por un nuevo tâ”œâ•‘nel, cuya armadura para sostener la losa que lo cubrirâ”œÃ­ estâ”œÃ­ siendo colocada. Esta obra se realizâ”œâ”‚ como acompaâ”œâ–’amiento de la estaciâ”œâ”‚n de cercanâ”œÂ¡as Zaragoza-Goya, siendo demolidos 310 metros de trinchera entre el râ”œÂ¡o Huerva y la iglesia citada. El anterior cubrimiento de esta infraestructura se llevâ”œâ”‚ a cabo entre 1959 y 1962. En 2012 se inaugurarâ”œÂ¡a el edificio de la terminal. Fuente: Heraldo de Aragâ”œâ”‚n.', 2011, 2011, 2011, 'Siglo XXI', 'UNIVERSIDAD', 41.64551900, -0.89331500, '0101000020E6100000F5D6C0560996ECBF2BF9D85DA0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37050990264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37050990264.webp', 'https://www.flickr.com/photos/zaragozaantigua/37050990264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24213, '&quot;Av. de Goya&quot; 1963', 'Imagen capturada durante las obras de duplicaciâ”œâ”‚n y soterramiento de la vâ”œÂ¡a del ferrocarril de Madrid a Barcelona en el punto donde se salvaba el desnivel de diez metros por donde fluâ”œÂ¡a entre acusada pendiente el râ”œÂ¡o Huerva. Por el tramo aâ”œâ•‘n al aire entre los nuevos tâ”œâ•‘neles del ferrocarril, correspondiente al puente sobre el Huerva, circula un convoy en direcciâ”œâ”‚n a la estaciâ”œâ”‚n de Miraflores. A la izquierda, traseras del antiguo nâ”¬â•‘ 45 de la la calle Zumalacâ”œÃ­rregui (que antes fuera avenida Central). A la derecha, traseras y lateral del antiguo nâ”¬â•‘ 18 de la calle de Benavente. Tras las obras, la reurbanizaciâ”œâ”‚n de la zona serâ”œÃ­ muy intensa, y el nuevo vial resultante sobre las vâ”œÂ¡as soterradas serâ”œÃ­ denominado aâ”œâ–’os despuâ”œÂ®s como avenida de Goya. De resultas de ello, la antigua calle de Goya habrâ”œÂ¡a de ser redenominada como de Jusepe Martâ”œÂ¡nez. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.64353800, -0.89031100, '0101000020E61000001B9C887E6D7DECBFDBDD03745FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40418089085.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40418089085.webp', 'https://www.flickr.com/photos/zaragozaantigua/40418089085/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24256, 'Cubrimiento Huerva 1925', 'Obras de cubrimiento del râ”œÂ¡o Huerva en la Gran Vâ”œÂ¡a, entre la calle Goya y la plaza Paraâ”œÂ¡so. 1925. Obras de rectificaciâ”œâ”‚n del cauce en la curva de "La Veneciana", demoliendo los antiguos muros para construir los nuevos. Fuente: AHPZ-Archivo Coyne, (SF), Estudio Coyne.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.64528900, -0.88988100, '0101000020E6100000E99D0AB8E779ECBFF9BB77D498D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14884268331.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14884268331.webp', 'https://www.flickr.com/photos/zaragozaantigua/14884268331/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24260, 'Gran Vâ”œÂ¡a 1925', 'Imagen de las obras de cubrimiento del râ”œÂ¡o Huerva en su tramo urbano, en la denominada "Primera zona", desde la "curva de la Veneciana", escenario de la captura fotogrâ”œÃ­fica (esa fâ”œÃ­brica quedaba a la derecha), hasta el puente de Santa Engracia. Al fondo, parcial vista de la fâ”œÃ­brica de sombreros que en 1931 sufrirâ”œÂ¡a un fatal incendio. Fuente visual: Carlos Blâ”œÃ­zquez, en "El Huerva, un râ”œÂ¡o con mucha historia".', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.64528300, -0.89024500, '0101000020E61000003EAE0D15E37CECBF17D522A298D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22076281825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22076281825.webp', 'https://www.flickr.com/photos/zaragozaantigua/22076281825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24262, 'Calle de Dato 1930', 'Penosa imagen, por su calidad fotogrâ”œÃ­fica, del antiguo principio de la calle de Eduardo Dato, con el camino de los Cubos y el brazal bajo de la acequia de la Romareda pasando justo delante. El muro del fondo delimitaba las antiguas instalaciones de la fâ”œÃ­brica de espejos de La Veneciana, detrâ”œÃ­s de las cuales estaba la flamante nueva Gran Vâ”œÂ¡a. A la izquierda, el edificio de dos alturas del antiguo nâ”¬â•‘ 2 de la calle de Dato. A la derecha no aparece ninguna seâ”œâ–’al edilicia, porque habâ”œÂ¡a un solar, en terrenos que fueran de la torre de Bernardo Fita. Fuente visual: Miguel Marâ”œÂ¡n Chivite, en el periâ”œâ”‚dico "Heraldo de Aragâ”œâ”‚n".', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.64597000, -0.89020400, '0101000020E61000009A9658198D7CECBF3B191C25AFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31695140424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31695140424.webp', 'https://www.flickr.com/photos/zaragozaantigua/31695140424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24267, 'Ferial 1931', 'Imagen del Ferial de las fiestas mayores de octubre, capturada en el amplio recinto del final de la Gran Vâ”œÂ¡a, delimitado por el brazal alto de la acequia de la Romareda, la lâ”œÂ¡nea de ferrocarril de Zaragoza a Barcelona, el brazal bajo de la acequia de la Romareda, y un vial en proceso de urbanizaciâ”œâ”‚n que luego serâ”œÃ­ denominado de Ricla (los inmuebles del fondo). Aquâ”œÂ¡ se ofrecâ”œÂ¡an al pâ”œâ•‘blico las tradicionales barracas fiesteras con atracciones de caballitos, toboganes, tiros al blanco, tâ”œâ”‚mbolas, churrerâ”œÂ¡as, y circos. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.64522700, -0.89151100, '0101000020E6100000B5C6A0134287ECBF83BF5FCC96D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36213333820.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36213333820.webp', 'https://www.flickr.com/photos/zaragozaantigua/36213333820/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24449, 'Avenida de Goya 1963', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 09/06/1963. "Inauguraciâ”œâ”‚n de la fâ”œÃ­brica de Galletas Cuâ”œÂ®tara." El empresario "galletero" Juan Gâ”œâ”‚mez Cuâ”œÂ®tara, mediante el "Plan Cuâ”œÂ®tara", se lanzâ”œâ”‚ a principios de los aâ”œâ–’os 60 a una importante expansiâ”œâ”‚n industrial en forma de media docena de nuevas pequeâ”œâ–’as fâ”œÃ­bricas en distintos puntos del paâ”œÂ¡s, al objeto de conseguir una buena cuota del mercado. Zaragoza fue una de las localidades elegidas. En la imagen, una caravana de transportes de la empresa aparcadas a la altura de la ubicaciâ”œâ”‚n de la fâ”œÃ­brica en la avenida de Goya, a la izquierda de la imagen. El cubrimiento de las vâ”œÂ¡as del tren era tan reciente, que aâ”œâ•‘n no habâ”œÂ¡a aceras, ni viales asfaltados. Coches aparcados, sâ”œÂ¡. A la derecha, el enorme arco de entrada a la Parroquia del Corazâ”œâ”‚n de Marâ”œÂ¡a. Al fondo, Fernando el Catâ”œâ”‚lico.', 1963, 1963, 1963, 'Anos 60', 'UNIVERSIDAD', 41.64596300, -0.89342200, '0101000020E610000077DCF0BBE996ECBF89B663EAAED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15218423765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15218423765.webp', 'https://www.flickr.com/photos/zaragozaantigua/15218423765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25010, 'Paseo de Ruiseâ”œâ–’ores 1922', 'Imagen capturada en el arbolado paseo de Ruiseâ”œâ–’ores, poco antes del despartidero donde comienza el camino antiguo de Cuarte, a espaldas del fotâ”œâ”‚grafo, junto al cerramiento de la casa de Juliâ”œÃ­n Escudero y el colegio Pompiliano de las Reverendas Madres Escolapias en construcciâ”œâ”‚n. A la derecha, interesante vista parcial del hotelito de Sebastiâ”œÃ­n Rodrâ”œÂ¡guez, que inicia la singular e irrepetible galerâ”œÂ¡a de viviendas unifamiliares construidas a principios de siglo en esta exclusiva zona residencial de la ciudad. Le siguen el de Raimundo Balet; el de â”œÃ¼ngel Anâ”œâ”‚s; la Villa Alta de Emilio Ostalâ”œÂ®; y el de la viuda de Collado.', 1922, 1922, 1922, 'Anos 20', 'UNIVERSIDAD', 41.63589200, -0.88975300, '0101000020E61000008A929048DB78ECBFDEE4B7E864D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48463896822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48463896822.webp', 'https://www.flickr.com/photos/zaragozaantigua/48463896822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24492, 'Antigua plaza de Espaâ”œâ–’a 1940', 'Las Fiestas de Primavera del aâ”œâ–’o 1940 fueron muy animadas, con rica variedad de desfiles de danzantes tâ”œÂ¡picos y festivales folclâ”œâ”‚ricos, bajo el velo protector oficial del diecinueve centenario de la fantâ”œÃ­stica llegada de la Virgen del Pilar en carne mortal a Zaragoza. En esta primaveral programaciâ”œâ”‚n se incluyâ”œâ”‚ la colocaciâ”œâ”‚n de la primera piedra de la nueva Casa Sindical de Aragâ”œâ”‚n en la avenida de Marina Moreno, y para darle respaldo visual, delante de ella desfilâ”œâ”‚, el 26 de mayo, una lucida cabalgata compuesta por las nueve Carrozas de la Producciâ”œâ”‚n Aragonesa, organizada por la Junta del Centenario (mariano), y la Central Nacional Sindicalista, cada una correspondiente con un gremio productivo. Entre ellas estaba la que ilumina esta imagen, la del Calzado, obra del reputado artista local Torres, que reproduce dos figuras de los cuentos tradicionales relacionadas con el sector del calzado: el Gato con Botas, y el zapato perdido de la princesa Cenicienta. En la imagen, la carroza referida, durante los preparativos de la cabalgata, en el entorno de la plaza que se iba a denominar de Espaâ”œâ–’a, pero que tras el golpe del 18-19 de julio de 1936 se tuvo que buscar otro nombre: San Francisco. Al fondo, el nuevo convento de los Carmelitas, que durante la guerra fue usado como cuartel de Comunicaciones, y que ahora estaba a punto de pasar a manos de los Hermanos de las Escuelas Cristianas. Fuente visual: Miguel Marâ”œÂ¡n Chivite, AMZ.', 1940, 1940, 1940, 'Anos 40', 'UNIVERSIDAD', 41.64073700, -0.89366700, '0101000020E61000003A765089EB98ECBF282B86AB03D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25328914079.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25328914079.webp', 'https://www.flickr.com/photos/zaragozaantigua/25328914079/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24930, 'Monumento a Bolâ”œÂ¡var 1970', 'Octubrina y soleada imagen capturada durante la inauguraciâ”œâ”‚n oficial del Monumento a Simâ”œâ”‚n Bolâ”œÂ¡var sito en el parque de Primo de Rivera, en su ubicaciâ”œâ”‚n entre la avenida de los Bearneses y el paseo de Mariano Renovales. Se trataba de una desafortunada râ”œÂ®plica en bronce del original busto de Bolâ”œÂ¡var, obra del escultor Pietro Tenerani (1836) instalado en el caraqueâ”œâ–’o Ministerio de Relaciones Exteriores. Entre la notable presencia de autoridades militares, religiosas y civiles destaca el alcalde Mariano Horno Liria, una amplia delegaciâ”œâ”‚n del râ”œÂ®gimen venezolano encabezada por el embajador Carlos Capriles y la câ”œâ”‚nsul general Josefina Achâ”œÂ®, y monseâ”œâ–’or Sâ”œÃ­nchez Espejo que bendijo la imagen. Como no podâ”œÂ¡a ser de otra forma, los discursos vincularon de forma altamente imaginativa la Zaragoza de la Virgen del Pilar y de los Sitios con el Libertador y con la lucha contra el materialismo y el comunismo. Cuando al Libertador se le saca de esos estrechos y carpetovetâ”œâ”‚nicos corsâ”œÂ®s, los problemas maduran.', 1970, 1970, 1970, 'Anos 70', 'UNIVERSIDAD', 41.63464100, -0.89330400, '0101000020E6100000FB592C45F295ECBFB2D991EA3BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15042212469.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15042212469.webp', 'https://www.flickr.com/photos/zaragozaantigua/15042212469/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24931, 'Calle Luis Vives 1974', 'Desde la altura de la torre de la Editorial Luis Vives, interesante imagen del panorama en el entorno del paso del Huerva por la zona. En primerâ”œÂ¡simo plano, el "quesito" de la referida editorial, con sus talleres aâ”œâ•‘n en funcionamiento. A la izquierda, la calle Luis Vives, precisamente. A su izquierda, entre la calle Andrâ”œÂ®s Piquer y Santa Teresa de Jesâ”œâ•‘s, el Grupo de Viviendas "Francisco Caballero", y una joya visual: asoman las Casas Baratas del Ensanche de 1934, â”œÂ®stas con su imagen de casita totalmente fuera de contexto. La lâ”œâ”‚gica sistâ”œÂ®mica se impuso poco despuâ”œÂ®s: fueron piqueteadas para mayor aprovechamiento vertical. Poco despuâ”œÂ®s, el puente sobre el Huerva, el Paseo de Mariano Renovales, las moles de los bloques "Marvel", la clâ”œÂ¡nica Quirâ”œâ”‚n, y el Parque Primo de Rivera.', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63812900, -0.89580400, '0101000020E6100000100874266DAAECBF89D00836AED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15042594298.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15042594298.webp', 'https://www.flickr.com/photos/zaragozaantigua/15042594298/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24936, 'Paseo de San Sebastiâ”œÃ­n 1976', 'Vista del paseo de San Sebastiâ”œÃ­n en el parque de Primo de Rivera, desde la altura de los antiguos accesos escalonados al Cabezo de Buenavista, donde se sitâ”œâ•‘a el monumento a Alfonso I el Batallador. En primer tâ”œÂ®rmino, la fuente trasladada desde la plaza de Basilio Paraâ”œÂ¡so en enero de 1974, y a la izquierda, el nuevo Jardâ”œÂ¡n Botâ”œÃ­nico. Al fondo la torre de la Feria Nacional de Muestras, destacando entre los edificios de La Romareda y el paseo de Fernando el Catâ”œâ”‚lico. El bulevar y resto de viales de este pulmâ”œâ”‚n verde se nos muestra apoderado por los vehâ”œÂ¡culos a motor de forma absoluta, una situaciâ”œâ”‚n que se mantuvo sin cambios hasta que en los primeros aâ”œâ–’os 80 un grupo de ciudadanos concienciados comenzaron a realizar semanalmente unas llamadas bicifestaciones, que con el lema Coches no, bicis sâ”œÂ¡ reivindicaban el desalojo de esos intrusos motorizados.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63452900, -0.89435400, '0101000020E6100000417FA1478C9EECBF8AAE0B3F38D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15513073492.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15513073492.webp', 'https://www.flickr.com/photos/zaragozaantigua/15513073492/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24940, 'Batallador 1925', '"Zaragoza. Monumento a Alfonso I. Autor: Josâ”œÂ® Bueno." Monumento impulsado por la Junta promotora del centenario 8 de la conquista cristiana de la ciudad, para ser colocado en el Cabezo del parque de Buenavista, fue tallado en mâ”œÃ­rmol de carrara por Josâ”œÂ® Bueno, con un potente pedestal en forma de torreâ”œâ”‚n neomedieval diseâ”œâ–’ado por Miguel â”œÃ¼ngel Navarro. Aunque el aniversario fue en 1918, el batallador estuvo emplazado en su sitio en 1923, en el modo y manera que la imagen ilustra. En 1927 se le colocarâ”œÃ­, sobre los cuatro sillares salientes del frontal, la figura de un leâ”œâ”‚n en bronce, obra del comandante de Infanterâ”œÂ¡a Virgilio Garrâ”œÃ­n, fundida en los talleres Averly. Insâ”œâ”‚litamente, 92 aâ”œâ–’os despuâ”œÂ®s sigue sin haber sido inaugurado por la oficialidad institucional municipal. Fuente visual: Archivo Juan Mora Insa, AHPZ.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63359100, -0.89335200, '0101000020E61000003F1EFAEE5696ECBF1D05888219D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22409809132.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22409809132.webp', 'https://www.flickr.com/photos/zaragozaantigua/22409809132/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24941, 'Cabezo de Buenavista Ca.1920', 'Imagen parcial del Cabezo de Buenavista con detalle de uno de los tres primitivos conjuntos de dobles escaleras y jardines diseâ”œâ–’ados en una zona de acusados desniveles que, mâ”œÃ­s adelante, recibirâ”œÂ¡a el nombre de "Jardâ”œÂ¡n de Invierno", inmediato al Canal Imperial, como destacado elemento del nuevo Parque Buenavista. El Cabezo queda a la izquierda de la imagen, tras un fuerte ascenso. Fuente visual: Archivo fotogrâ”œÃ­fico histâ”œâ”‚rico del SIPA (DARA-AHPZ).', 1920, 1920, 1920, 'Anos 20', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23397720424.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23397720424.webp', 'https://www.flickr.com/photos/zaragozaantigua/23397720424/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24942, 'Cabezo de Buenavista 1921', 'Imagen del Cabezo de Buenavista centrada en la zona de acusados desniveles que mâ”œÃ­s adelante recibirâ”œÂ¡a el nombre de "Jardâ”œÂ¡n de Invierno". Sus alabeadas escaleras y bancos de madera, los ornamentos vegetales, y â”œÃ­rboles de repoblaciâ”œâ”‚n, configuraban un singular, recogido y reconocido espacio dentro del nuevo Parque de Buenavista. Fuente visual: Foto F. Lâ”œâ”‚pez Blecua (Archivo A.C. "Paso a Nivel"), en www.rafaelcastillejo.com/', 1921, 1921, 1921, 'Anos 20', 'UNIVERSIDAD', 41.63180200, -0.89279000, '0101000020E610000052448655BC91ECBF11C64FE3DED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23735584070.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23735584070.webp', 'https://www.flickr.com/photos/zaragozaantigua/23735584070/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24948, 'Cabezo de Buenavista 1969', 'Imagen de Miguel Labordeta Subâ”œÂ¡as en el mirador del Cabezo de Buenavista, poco antes de su repentina muerte, tal vez (poema "La voz del poeta") velando largamente en duelo, oyendo en los silencios el ritmo pavoroso de los tiempos, acariciando la marea de las edades inmensas, rompiâ”œÂ®ndose en quejidos y maravillosas melodâ”œÂ¡as contra el humilde corazâ”œâ”‚n infortunado. Fuente visual: "Andalâ”œÃ­n, periâ”œâ”‚dico quincenal aragonâ”œÂ®s".', 1969, 1969, 1969, 'Anos 60', 'UNIVERSIDAD', 41.63227000, -0.89408600, '0101000020E610000073F7393E5A9CECBFF71E2E39EED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32610085656.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32610085656.webp', 'https://www.flickr.com/photos/zaragozaantigua/32610085656/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24990, 'Cabezo de Buenavista 1933', 'Imagen capturada en la muy ocasional pista de esquâ”œÂ¡ del Cabezo de Buenavista, que en el fresco enero de ese aâ”œâ–’o ofreciâ”œâ”‚ un marco incomparable e improvisado para la amateur prâ”œÃ­ctica de deporte blanco, sin que para ello fueran precisas inversiones pâ”œâ•‘blicas, ni privados patronazgos. El restaurant Las Palmeras, cerrado por fuera de temporada, no pudo beneficiarse del excepcional turisteo. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.63402400, -0.89312700, '0101000020E6100000429605137F94ECBF8670CCB227D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35624069571.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35624069571.webp', 'https://www.flickr.com/photos/zaragozaantigua/35624069571/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24991, 'Campeonatos Espaâ”œâ–’a Velocidad 1950', 'Cartel de la III fase de los Campeonatos Espaâ”œâ–’a Velocidad de motociclismo, celebrada en el parque Primo de Rivera el 4 de junio de 1950. El Moto Club Aragâ”œâ”‚n organizâ”œâ”‚ posteriormente en esa misma ubicaciâ”œâ”‚n el Gran Premio Internacional Nuestra Seâ”œâ–’ora del Pilar, entre 1952 y 1974. Fuente: charlescamberoque.unblog.fr/2016/03/06/les-grands-prix-de...', 1950, 1950, 1950, 'Anos 50', 'UNIVERSIDAD', 41.63263400, -0.89561100, '0101000020E6100000EB025E66D8A8ECBF392BA226FAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36416954642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36416954642.webp', 'https://www.flickr.com/photos/zaragozaantigua/36416954642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24995, 'Parque de Buenavista 1933', 'Imagen capturada en el parque de Buenavista y centrada en el evento "carrera de triciclos y automâ”œâ”‚viles infantiles" programado dentro de las Fiestas de Primavera que tuvo lugar el 23 de mayo de 1933, a las cinco de la tarde. La prueba discurriâ”œâ”‚ sobre una distancia de cien metros y todos los participantes fueron obsequiados con una caja de caramelos. En la categorâ”œÂ¡a de "automâ”œâ”‚viles de propulsiâ”œâ”‚n a pedal" resultâ”œâ”‚ ganador el niâ”œâ–’o Jesâ”œâ•‘s Cervello, y en la de "triciclos" el niâ”œâ–’o Josâ”œÂ® Marâ”œÂ¡a Cervello. Al fondo de la escena, el Cabezo de Buenavista con un aspecto parcial de las rampas que mediante escaleras le daban acceso desde la parte baja del parque donde se desarrollaba la carrera.', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.63486400, -0.89440000, '0101000020E6100000575BB1BFEC9EECBF31B43A3943D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52707152858.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52707152858.webp', 'https://www.flickr.com/photos/zaragozaantigua/52707152858/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24997, 'P.â”¬â•‘ de los Ruiseâ”œâ–’ores 1931', 'Inâ”œÂ®dita imagen capturada en el frondoso andador central del Jardâ”œÂ¡n Botâ”œÃ­nico que formaba parte de la Residencia de Estudiantes o Colegio Mayor de Cerbuna de la Universidad de Zaragoza. Al fondo, puerta de acceso abierta en el nâ”œâ•‘mero 23 del paseo de los Ruiseâ”œâ–’ores. El nuevo instituto MIguel Servet femenino proyectado en 1960 por el arquitecto Regino Borobio Ojeda respetâ”œâ”‚ parte de los jardines que formaban parte de este Jardâ”œÂ¡n Botâ”œÃ­nico, de forma que unas diez especies vegetales de las allâ”œÂ¡ plantadas han llegado hasta nuestros dâ”œÂ¡as.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63570000, -0.88967800, '0101000020E6100000E00F3FFF3D78ECBF9A081B9E5ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53178606148.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53178606148.webp', 'https://www.flickr.com/photos/zaragozaantigua/53178606148/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25003, 'P.â”¬â•‘ de Ruiseâ”œâ–’ores 1922', 'El efecto dominâ”œâ”‚ de la instalaciâ”œâ”‚n de los Depâ”œâ”‚sitos de Agua en la parte alta del Paseo de Cuâ”œÂ®llar, con la reparcelaciâ”œâ”‚n de la zona, permitiâ”œâ”‚ la creaciâ”œâ”‚n, en 1903, del proyecto de "barrio de Ruiseâ”œâ–’ores", junto al paseo de ese nombre, en una zona deshabitada de humanos. La nueva planta, planificada sobre terrenos como los de la antigua Torre de Marraco, estaba pensada como una extensiâ”œâ”‚n del cercano Paseo de Sagasta, con viviendas unifamiliares y estilosas para la alta burguesâ”œÂ¡a local, en una zona donde (tras eliminar una lecherâ”œÂ¡a y grandes establos) el aire era mâ”œÃ­s puro que abajo, en la lejana ciudad. Seis construcciones-piloto (Lucas Abâ”œâ”‚s, Viuda de Collado, Emilio Ostalâ”œÂ®, â”œÃ¼ngel Abâ”œâ”‚s, Raimundo Balet, y Sebastiâ”œÃ­n Rodrâ”œÂ¡guez), inauguraron esta exclusiva zona en 1905, y seâ”œâ–’alaron un camino pronto seguido por notable y selecta parroquia. En la imagen, el paseo de Ruiseâ”œâ–’ores. A la derecha, aspecto de los originales primeros "hotelitos" de la zona, localizados junto a la parte oeste de los Depâ”œâ”‚sitos, con visual insâ”œâ”‚lita del de Sebastiâ”œÃ­n Rodrâ”œÂ¡guez, y su llamativa torrecilla apuntada. A la izquierda, andamios de construcciâ”œâ”‚n del Colegio Pompiliano de las Escolapias, reciâ”œÂ®n llegadas al barrio. Como en la mayor parte de las construcciones de la zona, lo que hoy hay, poco mâ”œÃ­s de nueve dâ”œÂ®cadas despuâ”œÂ®s, poco ha de ver con lo que hubiera, o hubiese. Fuente visual: AHPZ, Archivo Gabriel Faci.', 1922, 1922, 1922, 'Anos 20', 'UNIVERSIDAD', 41.63598100, -0.88971000, '0101000020E6100000B8921D1B8178ECBF4EF04DD367D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21434044649.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21434044649.webp', 'https://www.flickr.com/photos/zaragozaantigua/21434044649/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25012, 'P.â”¬â•‘ de los Ruiseâ”œâ–’ores 1931', 'Inâ”œÂ®dita imagen capturada a la altura del nâ”œâ•‘mero 23 del paseo de los Ruiseâ”œâ–’ores, por donde a la izquierda se accedâ”œÂ¡a al Colegio Mayor de Cerbuna de la Universidad de Zaragoza, cuyo edificio se deja ver en el centro de la escena entre los monumentales acacias del paseo. La inmediata verja perimetral se abre mediante una puerta que permitâ”œÂ¡a el ingreso al Jardâ”œÂ¡n Botâ”œÃ­nico de la ciudad. Por el paseo desciende un autobâ”œâ•‘s de la lâ”œÂ¡nea que conectaba la plaza del Pilar con el Cabezo de Buenavista, de donde proviene. A la derecha, muros de los jardines de la antigua finca de Josâ”œÂ® Herrero, y justo en primer tâ”œÂ®rmino, punto en el que paseo de los Ruiseâ”œâ–’ores da principio al camino viejo de Cuarte, actual calle de Julio Cejador Frauca.', 1931, 1931, 1931, 'Anos 30', 'UNIVERSIDAD', 41.63589200, -0.88975300, '0101000020E61000008A929048DB78ECBFDEE4B7E864D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53166004310.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53166004310.webp', 'https://www.flickr.com/photos/zaragozaantigua/53166004310/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23636, 'Academia General Militar 1937', 'Prisioneros procedentes de Santa Quiteria (Tardienta) que fueron obligados a llevar esa pancarta a su llegada a Zaragoza. La Academia tenâ”œÂ¡a capacidad para albergar 2.000 presos y actuaba como centro de identificaciâ”œâ”‚n y clasificaciâ”œâ”‚n. En enero de 1938 se trasladâ”œâ”‚ el control al nuevo campo de concentraciâ”œâ”‚n de San Juan de Mozarrifar. Fuente visual: Delegaciâ”œâ”‚n de Prensa y Propaganda 5â”¬â•‘ Cuerpo de Ejâ”œÂ®rcito - Zaragoza.', 1937, 1937, 1937, 'Anos 30', NULL, 41.69927200, -0.87141700, '0101000020E6100000B7B585E7A5E2EBBF1781B1BE81D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938719875.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938719875.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938719875/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25077, 'Pardo Sastrâ”œâ”‚n 1930', 'Imagen del original monumento erigido en el parque de Buenavista al botâ”œÃ­nico Josâ”œÂ® Pardo Sastrâ”œâ”‚n (1822-1909). El busto, en mâ”œÃ­rmol, fue tallado por Pedro Sâ”œÃ­nchez Fustero sobre un pedestal en el que se puso la leyenda "Zaragoza al sabio botâ”œÃ­nico Pardo Sastrâ”œâ”‚n". A finales de 1929 fue emplazado muy cerca del "Chalet Buenavista" y el paseo del Canal, a la izquierda de la imagen. El paso del tiempo le hizo mala mella, e incluso mengua de algunos pedazos. En 1971, Francisco Rallo recibiâ”œâ”‚ el municipal encargo de restaurarlo, primero, y de modelar luego una reproducciâ”œâ”‚n en bronce, sobre nuevo pedestal en el que se puede leer la â”œÂ®tica inscripciâ”œâ”‚n "Pardo Sastrâ”œâ”‚n". Vandalizado periâ”œâ”‚dicamente por acâ”œÂ®falos sujetos, robado, devuelto, restaurado, pintarrajeado, limpiado, ensuciado, vuelto a limpiar... Su actual ubicaciâ”œâ”‚n es tambiâ”œÂ®n distinta: junto al antiguo paseo de los Plâ”œÃ­tanos del parque, ahora denominado de Manuel Azaâ”œâ–’a, casi en su confluencia con el paseo de los Bearneses. Fuente visual: Foto Martâ”œÂ¡nez ("Mundo Grâ”œÃ­fico", Madrid).', 1930, 1930, 1930, 'Anos 30', 'UNIVERSIDAD', 41.63350500, -0.89244400, '0101000020E6100000965D30B8E68EECBF1E6D1CB116D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22430934971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22430934971.webp', 'https://www.flickr.com/photos/zaragozaantigua/22430934971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25426, 'Paso MZA sobre el Huerva 1911', 'Imagen de la trinchera del ferrocarril de la compaâ”œâ–’â”œÂ¡a MZA (Madrid-Zaragoza-Alicante) a su paso sobre el râ”œÂ¡o Huerva mediante un puente metâ”œÃ­lico (en primer plano) entre la Huerta de Marraco (al fondo) y la Torre de Palomar (margen derecha del râ”œÂ¡o). El puente sobre las vâ”œÂ¡as daba continuidad al camino paralelo al râ”œÂ¡o Huerva, que conducâ”œÂ¡a al camino de los Cubos. (www.flickr.com/photos/zaragozaantigua/16804788840). Fuente visual: hemerotecadigital.bne.es/', 1911, 1911, 1911, 'Anos 10', 'UNIVERSIDAD', 41.64347700, -0.89031100, '0101000020E61000001B9C887E6D7DECBF355D4F745DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20511700974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20511700974.webp', 'https://www.flickr.com/photos/zaragozaantigua/20511700974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25487, 'Calle del Carmen 1957', 'Imagen centrada en la fachada del moderno grupo de viviendas de renta limitada proyectado por el arquitecto Josâ”œÂ® de Yarza Garcâ”œÂ¡a en el solar del nâ”¬â•‘ 18-20 de la calle del Carmen. A la izquierda, el bloque del nâ”¬â•‘ 24. A la derecha, vista parcial del edificio correspondiente al nâ”¬â•‘ 16 de la antigua avenida del Carmen. Fuente visual: arch. J. de Yarza', 1957, 1957, 1957, 'Anos 50', 'UNIVERSIDAD', 41.64699100, -0.89241200, '0101000020E6100000BEDA519CA38EECBF36E7E099D0D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37302488134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37302488134.webp', 'https://www.flickr.com/photos/zaragozaantigua/37302488134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25581, 'Pre-Avenida de Goya 1965', 'La calle de los ferrocarriles directos, o del ferrocarril de Madrid a Barcelona, o de Zaragoza a Barcelona, era el tramo mâ”œÃ­s o menos urbano que desde la estaciâ”œâ”‚n de Campo Sepulcro llegaba hasta el camino del Puente del Virrey. Cuando la ciudad engullâ”œâ”‚ los terrenos alrededor de la zanja ferroviaria, se planteâ”œâ”‚ soterrarla, cosa que puso muy contentos a los propietarios de los terrenos, que vieron abrâ”œÂ¡rseles los cielos del Dorado con el proceso de urbanizaciâ”œâ”‚n. En la imagen, aspecto de la trinchera del ferrocarril ya soterrado en lo que hoy es la Avenida de Goya, mâ”œÃ­s o menos a la altura de los nâ”œâ•‘meros 23 (izquierda) y 26 (derecha). La parte izquierda era mayormente antiguos talleres, la "Gran Fâ”œÃ­brica Mecâ”œÃ­nica de Calzado" de Josâ”œÂ® Sorrosal, y los huertos traseros de las fincas de la calle Benavente. Destaca la alta y aâ”œâ•‘n solitaria nueva construcciâ”œâ”‚n del nâ”¬â•‘ 37-43, que chaflanea con el Huerva. Al otro lado del râ”œÂ¡o, aspecto parcial del reciente Instituto Goya, y de los bloques a ambos lados del paseo Fernando el Catâ”œâ”‚lico. La parte derecha de la "calle" era un espacio hasta ese momento apenas las traseras de las construcciones de la calle Zumalacâ”œÃ­rregui (antigua avenida Central), con alguna precaria parcela y un par de pequeâ”œâ–’os bloques, hasta llegar al camino del Sâ”œÃ­bado. Poco a poco, esto se fue urbanizando y motorizando, y en 1969 esto serâ”œÃ­ denominado "Avenida Goya", desde el paseo del General Mola, hasta la Estaciâ”œâ”‚n Campo Sepulcro. Pero antes era asâ”œÂ¡. Hace apenas medio siglo. Fuente visual: Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Noviembre 1965.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64333300, -0.88952700, '0101000020E61000007616BD530177ECBF02B859BC58D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16336682234.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16336682234.webp', 'https://www.flickr.com/photos/zaragozaantigua/16336682234/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25582, 'Pre-Avenida de Goya 1965', 'Otra imagen de la soterrada trinchera del ferrocarril en lo que hoy es la Avenida de Goya, mâ”œÃ­s o menos a la altura del nâ”œâ•‘mero 26. Todas esas pequeâ”œâ–’as parcelas de la izquierda daban a la calle Zumalacâ”œÃ­rregui (antigua avenida Central), y llegaban hasta el antiguo Camino del Sâ”œÃ­bado y la calle Alar del Rey (antigua calle de la Cadena). En unos pocos aâ”œâ–’os toda esta zona quedarâ”œÃ­ irreconocible, restando sâ”œâ”‚lo en pie algunos bloques del fondo de la imagen, que hoy quedan como restos arqueolâ”œâ”‚gicos, fâ”œÃ­cilmente distinguibles por unas formas y alturas bien divergentes de las del actual entorno. Fuente visual: Archivo Municipal Zaragoza. Gerardo Sancho Ramo. 1965.', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64333300, -0.88952700, '0101000020E61000007616BD530177ECBF02B859BC58D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16372856114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16372856114.webp', 'https://www.flickr.com/photos/zaragozaantigua/16372856114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25591, 'Pasarela Huerva 1965', 'Imagen de la antigua pasarela sobre el râ”œÂ¡o Huerva que desde 1936 conectaba la calle de Zumalacâ”œÃ­rregui (al fondo) con la margen izquierda del râ”œÂ¡o (desde donde se ha capturado la imagen), y daba acceso al paseo de Fernando el Catâ”œâ”‚lico. El obraje que aparece alrededor estâ”œÃ­ relacionado con las obras de cubrimiento de las vâ”œÂ¡as del ferrocarril a Barcelona (a la derecha, fuera de plano), sobre la novâ”œÂ¡sima avenida de Goya, que conllevarâ”œÃ­n la desapariciâ”œâ”‚n de este paso peatonal. En el cartelâ”œâ”‚n que pende en primer tâ”œÂ®rmino puede leerse "Terminantemente prohibido estacionarse en la pasarela"', 1965, 1965, 1965, 'Anos 60', 'UNIVERSIDAD', 41.64372800, -0.89024500, '0101000020E61000003EAE0D15E37CECBF7FC2D9AD65D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33357677960.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33357677960.webp', 'https://www.flickr.com/photos/zaragozaantigua/33357677960/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23637, 'Josâ”œÂ® Millâ”œÃ­n-Astray 1930', 'Foto: Miguel Marâ”œÂ¡n Chivite. Academia General Militar de Zaragoza, 6 de junio de 1930. El coronel Josâ”œÂ® Millâ”œÃ­n-Astray (centro) conversa amigablemente con el rey Alfonso XIII. Este personaje se hizo câ”œÂ®lebre posteriormente por sus increpaciones fascistas y necrâ”œâ”‚filas, como "â”¬Ã­Viva la muerte!", lema apâ”œâ”‚crifo de la Legiâ”œâ”‚n Espaâ”œâ–’ola, fuerza militar creada por â”œÂ®l en 1920. Fuente: Archivo Heraldo de Aragâ”œâ”‚n.', 1930, 1930, 1930, 'Anos 30', NULL, 41.69952500, -0.87188200, '0101000020E610000006137F1475E6EBBF01DE02098AD94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14970758952.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14970758952.webp', 'https://www.flickr.com/photos/zaragozaantigua/14970758952/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25603, 'Claretianos en el tejado 1955', 'Tras mâ”œÃ­s de un aâ”œâ–’o de obras, el nuevo Templo de los Claretianos, va cobrando forma (diseâ”œâ–’o de Eduardo Lagunilla de Plandolit). Su fachada, orientada hacia el noreste, daba a la calle San Antonio Mâ”¬Â¬ Claret, luego Avenida de Goya, tras el cubrimiento de la trinchera del ferrocarril. En la imagen, un par de claretianos (distinguibles por sus hâ”œÃ­bitos oscuros, sus gafas, y su quietud) se han subido al tejado a ver câ”œâ”‚mo avanzan las cosas, mientras los obreros trabajan en el cerramiento de la câ”œâ•‘pula sobre el altar mayor. Al fondo, una buena panorâ”œÃ­mica del suroeste de la ciudad. A la derecha, visual de los edificios del entorno de la Avenida Valencia, Corona de Aragâ”œâ”‚n, y la actual Tomâ”œÃ­s Bretâ”œâ”‚n. Mucho mâ”œÃ­s al fondo, las estribaciones del Sistema Ibâ”œÂ®rico se recortan sobre el horizonte. Fuente visual: www.cormariazaragoza.es/?BODAS-DE-ORO-DE-LA-PARROQUIA', 1955, 1955, 1955, 'Anos 50', 'UNIVERSIDAD', 41.64522700, -0.89376300, '0101000020E6100000C1FEEBDCB499ECBF83BF5FCC96D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15612772816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15612772816.webp', 'https://www.flickr.com/photos/zaragozaantigua/15612772816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25610, 'Ensanche de Miralbueno 1932', 'Vista aâ”œÂ®rea de la zona denominada Ensanche de Miralbueno. La lâ”œÂ¡nea blanca que atraviesa la imagen es el trazado de las nuevas avenidas de Reina Victoria, y de Alfonso XIII. La plaza del centro es la de Espaâ”œâ–’a. En la esquina superior izquierda, la entrada al parque de Buenavista. Arriba, en el centro, el cuartel de Palafox. A la izquierda brilla el râ”œÂ¡o Huerva, y a la derecha se ve la zona de "casas baratas". En el â”œÃ­ngulo inferior derecho, la vâ”œÂ¡a del ferrocarril Madrid-Zaragoza. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1932, 1932, 1932, 'Anos 30', 'UNIVERSIDAD', 41.64237900, -0.89372200, '0101000020E61000001DE736E15E99ECBF8F519E7939D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19132531409.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19132531409.webp', 'https://www.flickr.com/photos/zaragozaantigua/19132531409/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25611, 'Trinchera del tren 1934', '"Paso superior de la Gran Vâ”œÂ¡a sobre el ferrocarril de M.Z.A. Destrucciâ”œâ”‚n del viejo y construcciâ”œâ”‚n del nuevo". Obras de acondicionamiento de las infraestructuras necesarias para la prolongaciâ”œâ”‚n de la Gran Vâ”œÂ¡a hasta la Romareda. Cruce de las actuales Gran Vâ”œÂ¡a y Fernando el Catâ”œâ”‚lico con avenida de Goya. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1934, 1934, 1934, 'Anos 30', 'UNIVERSIDAD', 41.64411200, -0.89184400, '0101000020E61000004948A46DFC89ECBF077B134372D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19138758758.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19138758758.webp', 'https://www.flickr.com/photos/zaragozaantigua/19138758758/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25612, 'Casas Baratas 1932', 'Conjunto de edificaciones acogidas a los beneficios de la legislaciâ”œâ”‚n de Casas Baratas y Econâ”œâ”‚micas del Ministerio de Trabajo, segâ”œâ•‘n proyecto de Miguel â”œÃ¼ngel Navarro y Secundino de Zuazo en 1928, para la Sociedad Zaragozana de Urbanizaciâ”œâ”‚n y Costrucciâ”œâ”‚n, constituida por los felices propietarios de los solares. Se hallan en la margen izquierda del râ”œÂ¡o Huerva (abajo), a la altura de la actual calle de Mariano Supervâ”œÂ¡a, donde subsiste una manzana y algunos fragmentos. Fuente: Plan general de ensanche de Zaragoza, 1934.', 1932, 1932, 1932, 'Anos 30', 'UNIVERSIDAD', 41.63903400, -0.89343400, '0101000020E6100000874D64E60297ECBF1B84B9DDCBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19314390592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19314390592.webp', 'https://www.flickr.com/photos/zaragozaantigua/19314390592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25616, 'Calle Bretâ”œâ”‚n 1933', 'Imagen de la calle Tomâ”œÃ­s Bretâ”œâ”‚n donde comenzaba, a la izquierda, la calle de la Virtud. Se trata de uno de los escenarios conflictuales de la "Jornada Revolucionaria" de Zaragoza en diciembre de 1933, lo que explica la presencia de la tropa de Guardia de Seguridad y Asalto, y la publicaciâ”œâ”‚n de la imagen en prensa de alcance estatal. Al fondo, y tras la calle Concepciâ”œâ”‚n Arenal, la calle Lorente, que entonces cerraba Bretâ”œâ”‚n. En 1967, la calle de la Virtud fue redenominada "Pilar Lorengar", en tiempos en que el cambio de nombre de viales no provocaba mucho debate. Fuente Visual: "Mundo Grâ”œÃ­fico" (Madrid).', 1933, 1933, 1933, 'Anos 30', 'UNIVERSIDAD', 41.64446600, -0.89593100, '0101000020E6100000581F0F7D77ABECBF25B1A4DC7DD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21988763079.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21988763079.webp', 'https://www.flickr.com/photos/zaragozaantigua/21988763079/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25622, 'C.â”¬â•‘ de los Cubos 1902', 'Dibujo publicitario con una singular y humeante vista de la "fâ”œÃ­brica de lonas para alpargatas y otros tejidos varios" de Castillo y Aznar domiciliada en el sinuoso camino de los Cubos nâ”¬â•‘ 280, en un despejado entorno junto al cauce del râ”œÂ¡o Huerva confrontando con la calle de la Luz, desde donde se habrâ”œÂ¡an tomado los esbozos para esta representaciâ”œâ”‚n. Aâ”œâ–’os despuâ”œÂ®s la fâ”œÃ­brica era ya solo de Câ”œÃ­ndido Castillo, especializada en gâ”œÂ®neros de punto, y finalmente de Hijos de Câ”œÃ­ndido Castillo, hasta la reurbanizaciâ”œâ”‚n de esta zona del antiguo ensanche de Miralbueno, cuando la fâ”œÃ­brica fue derribada y susutituida por modernos bloques de viviendas. Fuente visual: Oficina Espaâ”œâ–’ola de Patentes y Marcas.', 1902, 1902, 1902, 'Anos 1900', 'UNIVERSIDAD', 41.63992000, -0.89147900, '0101000020E6100000DD43C2F7FE86ECBF350708E6E8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25602635347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25602635347.webp', 'https://www.flickr.com/photos/zaragozaantigua/25602635347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25637, 'Calle de Cosme Blasco c.1973', 'Imagen capturada en altura desde el inmueble del nâ”¬â•‘ 9-11 de la calle de Ram de Viu y centrada en el lateral norteâ”œâ–’o del colegio de La Salle Gran Vâ”œÂ¡a lindero con la calle de Cosme Blasco, donde destaca la singular torre, que sobresale por encima de la gran nave de la iglesia, y de las dependencias de residencia y formaciâ”œâ”‚n de los Hermanos de las Escuelas Cristianas, establecidos en 1943 en lo que originalmente fue el nuevo Convento e Iglesia de los Carmelitas Descalzos. El aspecto que luce en la imagen era el resultado de unas recientes e importantes modificaciones y aâ”œâ–’adidos a la estructura original, que llevaron a ser reinaugurado unos pocos aâ”œâ–’os antes (1969). Al fondo, inmuebles de los nâ”œâ•‘meros 4 y 2 de la calle de La Salle. En primer tâ”œÂ®rmino, amplia zona verde integrante del gran complejo de la moderna parroquia del Carmen y San Josâ”œÂ® de los Carmelitas Descalzos, donde poco despuâ”œÂ®s y en una parte serâ”œÂ¡an construidos los modernos bloques de los nâ”œâ•‘meros 19 y 21 de la calle de Santa Teresa de Jesâ”œâ•‘s. A la derecha, casual vista de la esquina en ladrillo, recayente a esa calle, del referido complejo del Carmen y San Josâ”œÂ®, o parroquia de San Juan de la Cruz.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64032600, -0.89282100, '0101000020E610000013D38558FD91ECBFA663CE33F6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48389574527.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48389574527.webp', 'https://www.flickr.com/photos/zaragozaantigua/48389574527/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25641, 'P.â”¬â•‘ de Fernando el Catâ”œâ”‚lico 1958', 'Imagen tomada en el bulevar del paseo de Fernando el Catâ”œâ”‚lico con el objetivo centrado en el tramo de los nâ”œâ•‘meros impares entre las calles de San Juan de la Cruz y de Mariano Barbasâ”œÃ­n. Destaca el solar donde poco despuâ”œÂ®s se construirâ”œÂ¡a el bloque del nâ”œâ•‘mero 27 del paseo. La continuidad peatonal del bulevar requerâ”œÂ¡a una especial atenciâ”œâ”‚n para evitar no interrumpir el trâ”œÃ­fico rodado.', 1958, 1958, 1958, 'Anos 50', 'UNIVERSIDAD', 41.64226700, -0.89363600, '0101000020E610000079E75086AA98ECBF672618CE35D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53538453036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53538453036.webp', 'https://www.flickr.com/photos/zaragozaantigua/53538453036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26015, 'Vista aâ”œÂ®rea Corona de Aragâ”œâ”‚n 1991', 'Foto: Archivo Taumar (Irene Taulâ”œÂ®s y Rafael Margalâ”œÂ®). Vista aâ”œÂ®rea parcial del distrito Universidad, con la calle Corona de Aragâ”œâ”‚n en el centro, de izquierda a derecha. Abajo a la izquierda, acceso principal de la Ciudad Universitaria. Abajo a la derecha, paseo de Fernando el Catâ”œâ”‚lico. Fuente: www.facebook.com/photo.php?fbid=1687671024789930&set=...', 1991, 1991, 1991, 'Anos 90', 'UNIVERSIDAD', 41.64262500, -0.89519400, '0101000020E6100000E06932E36DA5ECBFC74B378941D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22418696871.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22418696871.webp', 'https://www.flickr.com/photos/zaragozaantigua/22418696871/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26022, 'Cabezo de Buena Vista c.1962', 'Vista del parque Primo de Rivera desde el Cabezo de Buena Vista. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1962, 1962, 1962, 'Anos 60', 'UNIVERSIDAD', 41.63366800, -0.89333800, '0101000020E610000000C5C8923996ECBFC84274081CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321614842.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321614842.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321614842/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21926, 'Editorial Luis Vives 1946', 'Desde la prismâ”œÃ­tica torre de ladrillo caravista de la novâ”œÂ¡sima Feria de Muestras, un vistazo hacia el "quesito" formado por Fernando el Catâ”œâ”‚lico (arbolado, tranquilâ”œÂ¡simo, rueda un tranvâ”œÂ¡a serie 90 con remolque de la lâ”œÂ¡nea 11 "Parque"), el râ”œÂ¡o Huerva a la derecha (la calle Manuel Lasala no existe aâ”œâ•‘n), y la calle Luis Vives (reciâ”œÂ®n abierta, sin el puente del mismo nombre que conectarâ”œÃ­ luego con el Paseo Mariano Renovales). Una parte de este quesito, propiedad municipal y denominado "Campo de la Victoria", fue ofrecido en subasta a la nueva y marista Editorial Luis Vives en 1940, "cocinâ”œÃ­ndola" lo suficiente para que nadie mâ”œÃ­s se presentara. Y la ganaron. La gran nave de 75x25 m. que allâ”œÂ¡ se levantâ”œâ”‚ fue obra de Regino y Josâ”œÂ® Borobio, y ya en 1941 la Editorial estaba tirando tinta. Las instalaciones crecieron luego hasta por tres en tamaâ”œâ–’o, incluyendo una torre de 45 m. de altura, que aparece en algunas imâ”œÃ­genes de los aâ”œâ–’os 60. En 1975 la Editorial se trasladâ”œâ”‚ a la Carretera de Madrid, donde hoy sigue. Todo el quesito fue vendido a un precio interesante, y fue urbanizado en la forma de los tremendos bloques de viviendas que ahora existen. Justo detrâ”œÃ­s de la Editorial, blanquea el importante Grupo de Viviendas "Francisco Caballero", de Allâ”œÃ­negui y Yarza (1941). Junto a ellas, casas y palacetes unifamiliares que caracterizaban el entorno de la actual calle Ram de Viu. De todos ellos sâ”œâ”‚lo perdura uno, la "Casa Familiar tipo 1", obra de Miguel â”œÃ¼ngel Navarro (1929). Un poco mâ”œÃ­s al fondo, las caracterâ”œÂ¡sticas, por modestas, viviendas obreras del industrial Camino del Sâ”œÃ­bado. Es visible la chimenea de una fâ”œÃ­brica de curtidos, orilla al Huerva, en Juan Pablo Bonet. Al fondo del todo, a la derecha, la masa oscura del Parque Pignatelli, desde donde, en descenso, empezaban a levantarse los grandes bloques que caracterizan al actual Paseo Sagasta. Son visibles los remates de los que se levantan en el cruce de Camino de las Torres con Sagasta. Es visible tambiâ”œÂ®n el enorme depâ”œâ”‚sito de', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63748000, -0.89855000, '0101000020E6100000FE43FAEDEBC0ECBF52EDD3F198D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14852586062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14852586062.webp', 'https://www.flickr.com/photos/zaragozaantigua/14852586062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21939, 'Feria de Muestras 1941', 'En 1934 tuvo lugar la Iâ”¬Â¬ Feria de Muestras Aragonesa, en la Lonja. Al aâ”œâ–’o siguiente, la IIâ”¬Â¬. En 1936, la guerra motivada por el fracaso del Golpe militar, paralizâ”œâ”‚ tambiâ”œÂ®n esta feria. Desde 1939, el nuevo Râ”œÂ®gimen fascista ganador de la guerra quiso recuperarla, pero dâ”œÃ­ndole un carâ”œÃ­cter "nacionalista". Asâ”œÂ¡, en 1941 tuvo lugar la Iâ”¬Â¬ Feria Nacional de Muestras, del 15 al 31 de mayo, en un recinto con pretensiones de permanencia, el denominado "Palacio de la Producciâ”œâ”‚n Aragonesa", junto al parque al que volvieron a denominar de Primo de Rivera (durante la Repâ”œâ•‘blica fue "Parque de Buena Vista"). En la imagen, dibujo del nuevo recinto ferial, proyectado por Regino y Josâ”œÂ® Borobio Ojeda y Josâ”œÂ® Beltrâ”œÃ­n, que quedarâ”œÃ­ terminado en 1958. Fuente visual: "Aragâ”œâ”‚n: revista grâ”œÃ­fica de cultura aragonesa" (Aâ”œâ–’o XVII, Nâ”¬â•‘ 171, junio-julio 1941).', 1941, 1941, 1941, 'Anos 40', 'UNIVERSIDAD', 41.63742200, -0.89889500, '0101000020E6100000A4367172BFC3ECBF1EE0490B97D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15501207198.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15501207198.webp', 'https://www.flickr.com/photos/zaragozaantigua/15501207198/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21946, 'Fuente de la Princesa 1946', 'Tras su periplo por la ciudad, la Fuente de la Princesa o de Neptuno reposa hoy en el parque Grande. Lo hace desde 1946. Fuente: tausiet.blogspot.com.es/2016/01/la-historia-errante-de-ne...', 1946, 1946, 1946, 'Anos 40', 'UNIVERSIDAD', 41.63533700, -0.89719600, '0101000020E6100000B743C362D4B5ECBF29780AB952D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15883391825.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15883391825.webp', 'https://www.flickr.com/photos/zaragozaantigua/15883391825/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21978, 'Feria de Muestras 1941', 'Del 15 al 31 de mayo de 1941 tuvo lugar la Iâ”¬Â¬ Feria Nacional de Muestras, en un nuevo recinto con pretensiones de permanencia, denominado "Palacio de la Producciâ”œâ”‚n Aragonesa", junto al parque redenominado de Primo de Rivera (antes "de Buena Vista"). La imagen, muy daâ”œâ–’ada, representa el cartel oficial de esta muestra, cuyo diseâ”œâ–’o fue obra de Manuel Bayo Marâ”œÂ¡n ("Bayo"). De la reproducciâ”œâ”‚n y tirada se encargâ”œâ”‚ "Industrias del Cartonaje C.A. Zaragoza". Vertebra la composiciâ”œâ”‚n una estilizada representaciâ”œâ”‚n de la esquinera fachada del nuevo recinto ferial, proyectado por Regino y Josâ”œÂ® Borobio Ojeda, y Josâ”œÂ® Beltrâ”œÃ­n, con la significativa torre aâ”œâ•‘n sin el acristalado remate, y los porches de acceso. Flanquean la torre (que, ademâ”œÃ­s, representa el "I" de la Iâ”¬Â¬ ediciâ”œâ”‚n ferial), los sâ”œÂ¡mbolos propiciatorios de la prosperidad (Atenea), el comercio (Vara de Hermes), la agricultura (una espiga dorada por el sol), y la industria (mecâ”œÃ­nica rueda dentada). A ambos lados, las banderas del râ”œÂ®gimen franquista: la nacional, la de FET-JONS, y la del Requetâ”œÂ®. Por encima, las oscuras alas de una feroz â”œÃ­guila imperial, en actitud sobreprotectora, poco amable, nazi. Fuente visual: www.todocoleccion.net/', 1941, 1941, 1941, 'Anos 40', 'UNIVERSIDAD', 41.63732000, -0.89852900, '0101000020E6100000213EB0E3BFC0ECBF1A8BA6B393D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25168769745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25168769745.webp', 'https://www.flickr.com/photos/zaragozaantigua/25168769745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22000, 'Paseo Fernando el Catâ”œâ”‚lico 1949', 'Vista desde la torre de la Feria de Muestras, con el arbolado paseo de Fernando el Catâ”œâ”‚lico que se extiende desde la plaza del Emperador Carlos V, en primer tâ”œÂ®rmino, hasta el fondo de la de San Francisco. En el centro, el pionero bloque de los nâ”œâ•‘meros 31-39 de la calle del Arzobispo Apaolaza en un entorno rururbano todavâ”œÂ¡a marcado por la acequia de la Romareda aâ”œâ•‘n al aire. A la izquierda, el despejado campus de la Universidad. A la derecha, la manzana de la editorial Luis Vives y el Grupo de Viviendas Francisco Caballero detrâ”œÃ­s. Sobre el firme, tendido tranviario de la lâ”œÂ¡nea 11 "Parque", en el acceso al bucle de la terminal sita en la plaza del Emperador Carlos.', 1949, 1949, 1949, 'Anos 40', 'UNIVERSIDAD', 41.63851100, -0.89803700, '0101000020E61000006C223317B8BCECBF71917BBABAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33647517682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33647517682.webp', 'https://www.flickr.com/photos/zaragozaantigua/33647517682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
